import Vue from "vue";
import Router from "vue-router";
import Home from "./views/Home";
import Projects from "./views/Projects";

Vue.use(Router);

export default new Router({
    routes: [
        {
            path: "/",
            name: "home",
            component: Home
        },
        {
            path: "/projects",
            name: "projects",
            component: Projects
        }
    ]
})